B.XC=new A.y(B.I,"Edilgen \xe7at\u0131 neden \xf6nemlidir",'Havac\u0131l\u0131k \u0130ngilizcesi b\xfcy\xfck \xf6l\xe7\xfcde **edilgen \xe7at\u0131**ya dayan\u0131r. Bak\u0131m k\u0131lavuzlar\u0131, kontrol listeleri ve ATC talimatlar\u0131, eylemi ger\xe7ekle\u015ftirenden de\u011fil **yap\u0131lan eylemin daha \xf6nemli** oldu\u011fu durumlarda edilgen yap\u0131lar\u0131 s\u0131k\xe7a kullan\u0131r.\n\n\xd6rne\u011fin, "The fuel filter must be replaced" ifadesi "You must replace the fuel filter" ifadesinden daha kesin ve profesyoneldir.',null,null,null)
