B.VP=new A.y(B.I,"NOTAM nedir?","Bir **NOTAM** (Notice to Air Missions \u2014 Havac\u0131l\u0131k Operasyonlar\u0131na Bildirim), u\xe7u\u015f operasyonlar\u0131yla ilgili personele da\u011f\u0131t\u0131lan resmi bir bildirimdir. Herhangi bir havac\u0131l\u0131k tesisi, hizmet, prosed\xfcr veya tehlike hakk\u0131nda olu\u015fturma, durum veya de\u011fi\u015fiklik bilgisi i\xe7erir.\n\nOkuma anlama sorular\u0131 \xe7o\u011funlukla NOTAM tarz\u0131 metinler ya da bak\u0131m/muayene belgeleri kullan\u0131r.",null,null,null)
B.WG=new A.y(B.w,"\ud83d\udccb NOTAM Yap\u0131s\u0131",'Bir NOTAM \u015funlar\u0131 i\xe7erir:\n**Q)** \u2014 Konu/durum/trafik kodlar\u0131\n**A)** \u2014 Konum (ICAO kodu)\n**B)** \u2014 Ba\u015flang\u0131\xe7 tarihi/saati\n**C)** \u2014 Biti\u015f tarihi/saati\n**E)** \u2014 Tam metin a\xe7\u0131klamas\u0131\n\n\xd6rnek yap\u0131:\n"A0123/24 NOTAMN\nQ) LTAA/QMRLC/IV/NBO/A/000/999/4059N02858E005\n**A) LTBA B) 2401150600 C) 2401152359**\n**E) RWY 36L/18R CLOSED FOR MAINTENANCE"**',null,null,null)
B.VX=new A.y(B.w,"\ud83d\udd0d Okuma Anlama Stratejisi",'Herhangi bir havac\u0131l\u0131k metni i\xe7in (NOTAM, rapor, k\u0131lavuz al\u0131nt\u0131s\u0131):\n1. **\xd6nce tara** \u2014 belge t\xfcr\xfcn\xfc ve konuyu belirle\n2. **Soruyu oku, sonra metni yeniden oku** \u2014 neye bakaca\u011f\u0131n\u0131 bil\n3. **Anahtar ger\xe7ekleri bul** \u2014 tarihler, yerler, k\u0131s\u0131tlamalar, gereklilikler\n4. **Olumsuzlamalara dikkat et** \u2014 "not", "except", "unless" anlam\u0131 tamamen de\u011fi\u015ftirir\n5. **Varsay\u0131mdan ka\xe7\u0131n** \u2014 yaln\u0131zca verilen metinden yan\u0131t ver',null,null,null)
B.NA=new A.a5("Detailed Inspection (DI) is an intensive examination of a specific item to detect damage, failure or irregularity.","Detayl\u0131 Muayene (DI), hasar, ar\u0131za veya d\xfczensizlikleri tespit etmek i\xe7in belirli bir \xfcr\xfcn\xfcn yo\u011fun incelemesidir.","detect damage, failure or irregularity")
B.NU=new A.a5("Available lighting is normally supplemented with a direct source of good lighting at an intensity deemed appropriate.","Mevcut ayd\u0131nlatma normalde uygun g\xf6r\xfclen yo\u011funlukta iyi bir ayd\u0131nlatma kayna\u011f\u0131yla desteklenir.","supplemented")
B.a_W=s([B.NA,B.NU],t.l)
B.Xg=new A.y(B.G,"\xd6rnek Pasaj",null,B.a_W,null,null)
B.WN=new A.y(B.am,"\u2708\ufe0f Okuma \u0130pu\xe7lar\u0131",'Soru t\xfcrlerine dikkat et:\n\u2022 **"Ana ama\xe7 nedir?"** \u2192 a\xe7\u0131l\u0131\u015f tan\u0131m c\xfcmlesini ara\n\u2022 **"Hangisi GEREKL\u0130 DE\u011e\u0130LD\u0130R?"** \u2192 listeyi bul ve eksik/d\u0131\u015flanan \xf6geyi belirle\n\u2022 **"Metne g\xf6re..."** \u2192 yan\u0131t a\xe7\u0131k\xe7a belirtilmi\u015f olmal\u0131, \xe7\u0131kar\u0131m yap\u0131lmamal\u0131\n\u2022 **"X neyi inceler?"** \u2192 anahtar fiilin do\u011frudan nesnesini bul',null,null,null)
