B.Vv=new A.y(B.I,"Havaliman\u0131 ortam\u0131n\u0131n kesin terminolojisi vard\u0131r","Yer operasyonlar\u0131 kelime bilgisi, bo\u015fluk doldurma ve okuma anlama sorular\u0131nda yo\u011fun bi\xe7imde s\u0131nan\u0131r. **Taksi yolu (taxiway)**, **pist (runway)**, **apron** ve **ramp** aras\u0131ndaki fark\u0131 bilmek hem g\xfcvenli operasyonlar hem de s\u0131nav ba\u015far\u0131s\u0131 i\xe7in \u015fartt\u0131r.",null,null,null)
B.Tu=new A.y(B.w,"\ud83d\udeec Havaliman\u0131 Hareket Alanlar\u0131","**Runway** \u2014 paved surface for takeoff and landing\n**Taxiway** \u2014 paved path connecting runways to aprons (named A, B, C\u2026)\n**Apron (Ramp)** \u2014 area for parking, loading, servicing aircraft\n**Holding Bay** \u2014 area where aircraft wait before entering runway\n**Threshold** \u2014 beginning of the runway available for landing\n**Displaced Threshold** \u2014 landing threshold moved from physical runway end\n**Stopway** \u2014 paved area beyond runway end, usable for stopping only",null,null,null)
