B.Y6=new A.y(B.I,"Neden fonetik alfabe kullan\u0131l\u0131r?",'Havac\u0131l\u0131k telsiz haberle\u015fmesinde benzer seslerin kar\u0131\u015ft\u0131r\u0131lmamas\u0131 kritiktir. "B" ve "D", "M" ve "N" gibi harfler g\xfcr\xfclt\xfcl\xfc bir ortamda kolayca kar\u0131\u015fabilir.\n\nNATO fonetik alfabesi, her harfe \xf6zg\xfcn bir kelime atayarak bu sorunu \xe7\xf6zer. ICAO taraf\u0131ndan standartla\u015ft\u0131r\u0131lm\u0131\u015ft\u0131r ve t\xfcm havac\u0131lar taraf\u0131ndan kullan\u0131l\u0131r.',null,null,null)
B.Xs=new A.y(B.w,"\ud83d\udd24 NATO Fonetik Alfabe",'**A** Alpha  **B** Bravo  **C** Charlie  **D** Delta  **E** Echo\n**F** Foxtrot  **G** Golf  **H** Hotel  **I** India  **J** Juliett\n**K** Kilo  **L** Lima  **M** Mike  **N** November  **O** Oscar\n**P** Papa  **Q** Quebec  **R** Romeo  **S** Sierra  **T** Tango\n**U** Uniform  **V** Victor  **W** Whiskey  **X** X-ray  **Y** Yankee  **Z** Zulu\n\n**Say\u0131 telaffuzu (ICAO):**\n0 \u2192 ZE-RO  1 \u2192 WUN  2 \u2192 TOO  3 \u2192 TREE\n4 \u2192 FOW-ER  5 \u2192 FIFE  6 \u2192 SIX  7 \u2192 SEV-EN\n8 \u2192 AIT  9 \u2192 NIN-ER\n\n**U\xe7u\u015f kodu \xf6rne\u011fi:** THY 234 \u2192 "Turkish TOO TREE FOW-ER"',null,null,null)
