B.Wm=new A.y(B.I,"Yer hareketi neden kritiktir?","Havaliman\u0131 yer hareketi, u\xe7u\u015f emniyeti a\xe7\u0131s\u0131ndan en riskli fazlardan biridir. Pist ihlalleri (runway incursions) d\xfcnya genelinde ciddi kazalara neden olmaktad\u0131r. Bu nedenle yer hareketiyle ilgili talimatlar\u0131n tam olarak anla\u015f\u0131lmas\u0131 hayati \xf6nem ta\u015f\u0131r.",null,null,null)
B.Xi=new A.y(B.w,"\ud83d\udeec Temel Yer Hareketi Talimatlar\u0131",'**Piste giri\u015f/\xe7\u0131k\u0131\u015f:**\n\u2022 **Line up** (UK) / **Position** (US) \u2192 piste gir ve kalk pozisyonuna ge\xe7\n\u2022 **Line up and wait** \u2192 piste gir, bekle (h\xe2l\xe2 kalk\u0131\u015f onay\u0131 yok)\n\u2022 **Cleared for take-off** \u2192 kalk\u0131\u015f onayland\u0131\n\u2022 **Vacate** \u2192 pisti terk et (inis sonras\u0131)\n\u2022 **Backtrack** \u2192 pist \xfczerinde geri git\n\n**Taksiyolu talimatlar\u0131:**\n\u2022 **Taxi to** \u2192 taksilen git\n\u2022 **Hold short of runway XX** \u2192 XX pistinin kenar\u0131nda dur (piste girme)\n\u2022 **Hold position** \u2192 oldu\u011fun yerde dur\n\u2022 **Give way to** \u2192 yol ver\n\u2022 **Cross runway XX** \u2192 XX pistini ge\xe7\n\n**Dikkat edilecekler:**\n\u2022 "Hold short of runway" \u2192 **piste girilmez**, onay beklenir\n\u2022 T\xfcm pist talimatlar\u0131 readback yap\u0131lmal\u0131d\u0131r',null,null,null)
