B.Xj=new A.y(B.I,"Her METAR unsurunun kesin bir anlam\u0131 vard\u0131r","\xc7eviri sorular\u0131 \xe7o\u011funlukla METAR veya TAF kodlar\u0131n\u0131 yorumlaman\u0131z\u0131 ve d\xfcz dille ifade etmenizi \u2014 ya da bir hava g\xf6zleminin do\u011fru T\xfcrk\xe7e \xe7evirisini belirlemenizi ister.\n\nBir METAR'in her unsuru sabit s\u0131rayla gelir ve kesin bir anlam ta\u015f\u0131r. S\u0131ray\u0131 kar\u0131\u015ft\u0131rmak veya bir k\u0131saltmay\u0131 yanl\u0131\u015f yorumlamak puan kaybettirir.",null,null,null)
