B.Os=new A.a5('"Declaring minimum fuel, request direct routing to reduce flight time."',"Minimum yak\u0131t bildirimi \u2014 acil de\u011fil ama \xf6ncelik istiyor.","minimum fuel \u2026 direct routing")
