B.VE=new A.y(B.w,"\u26a1 Havac\u0131l\u0131kta Ko\u015ful Yap\u0131lar\u0131",'**Tip 1 (Ger\xe7ek ko\u015ful):** "If + present, will/shall + infinitive"\n\u2192 "If the engine fails, the crew will initiate the emergency procedure."\n\n**Tip 2 (Varsay\u0131msal):** "If + past simple, would + infinitive"\n\u2192 "If the fuel ran out, we would have to divert immediately."\n\n**Tip 3 (Ge\xe7mi\u015fe ait):** "If + past perfect, would have + past participle"\n\u2192 "If the warning had been detected earlier, the crew would have diverted in time."\n\n**Unless** = "if \u2026 not" \u2192 "Unless ATC clears the runway, the aircraft cannot land."\n\n**Provided that / As long as** = ko\u015ful ba\u011flay\u0131c\u0131lar\n\u2192 "The approach may continue provided that visibility exceeds 550 metres."\n\n**Havac\u0131l\u0131ktaki ba\u011flam:**\nAcil durum kontrol listeleri, teknik dok\xfcmanlar ve ATC talimatlar\u0131 s\u0131kl\u0131kla ko\u015ful yap\u0131s\u0131 kullan\u0131r.',null,null,null)
B.PI=new A.a5('"If the fire warning activates, the crew shall discharge the extinguisher and land as soon as possible."',"Yang\u0131n uyar\u0131s\u0131 etkinle\u015firse, m\xfcrettebat s\xf6nd\xfcr\xfcc\xfcy\xfc devreye almal\u0131 ve m\xfcmk\xfcn olan en k\u0131sa s\xfcrede inmeli.","If \u2026 activates \u2026 shall")
B.Np=new A.a5('"Unless the hydraulic pressure is restored, gear extension will be performed manually."',"Hidrolik bas\u0131n\xe7 geri gelmezse, ini\u015f tak\u0131m\u0131 manuel olarak indirilecek.","Unless \u2026 is restored \u2026 will be performed")
B.OK=new A.a5('"The landing may be continued provided that the reported RVR is not less than 550 metres."',"Bildirilen RVR 550 metreden az olmad\u0131\u011f\u0131 s\xfcrece ini\u015f s\xfcrd\xfcr\xfclebilir.","provided that \u2026 is not less than")
