B.V_=new A.y(B.I,"ATIS nedir?","ATIS (Automatic Terminal Information Service), havaliman\u0131 bilgilerini otomatik olarak yay\u0131nlayan ses sistemidir. Pilotlar ilk temas \xf6ncesinde ATIS'i alarak havaliman\u0131n\u0131n g\xfcncel bilgilerini \xf6\u011frenirler.\n\nHer g\xfcncellenen ATIS'e bir harf verilir (Alpha, Bravo... Zulu). Pilot ATC'ye \"information Charlie\" gibi hangi ATIS'i ald\u0131\u011f\u0131n\u0131 belirtir.",null,null,null)
B.TS=new A.y(B.w,"\ud83d\udcfb ATIS \u0130\xe7eri\u011fi ve Standart Format",'**Tipik ATIS i\xe7eri\u011fi (s\u0131rayla):**\n1. Airport name + ATIS designator (harf)\n2. Time of observation (UTC)\n3. Wind direction & speed\n4. Visibility\n5. Weather phenomena (rain, fog, etc.)\n6. Cloud cover & ceiling\n7. Temperature & dewpoint\n8. QNH (altimeter setting)\n9. Active runway(s)\n10. NOTAMs (gerekirse)\n11. ATIS designator tekrar ("this is information Charlie")\n\n**Kritik kelimeler:**\n\u2022 "Ceiling [X] feet broken/overcast" \u2192 bulut tavan\u0131\n\u2022 "Visibility [X] metres/km" \u2192 g\xf6r\xfc\u015f mesafesi\n\u2022 "Wind [dir] degrees [speed] knots gusting [X]" \u2192 r\xfczgar\n\u2022 "QNH [xxxx]" \u2192 bas\u0131n\xe7 ayar\u0131\n\u2022 "Expect ILS approach runway XX" \u2192 beklenen yakla\u015fma\n\u2022 "Caution: construction work / bird activity" \u2192 uyar\u0131',null,null,null)
