B.Oq=new A.a5('Pilot response: "Turkish 5, information Delta received."',"Pilot ATIS'i ald\u0131\u011f\u0131n\u0131 bildiriyor \u2014 ATC tekrar hava bilgisi vermez.","information Delta received")
