B.Vu=new A.y(B.I,"\u0130leri metinler karma\u015f\u0131k dilbilgisi yap\u0131lar\u0131 kullan\u0131r","Havac\u0131l\u0131k belgeleri, kaza raporlar\u0131 ve ICAO yay\u0131nlar\u0131, birden fazla yan c\xfcmleyi bir araya getiren karma\u015f\u0131k c\xfcmle yap\u0131lar\u0131 kullan\u0131r. \u0130leri d\xfczeyde, hem anlama hem de \xfcretim sorular\u0131nda bunlar\u0131 do\u011fru bir \u015fekilde ele almal\u0131s\u0131n\u0131z.",null,null,null)
